function speakerMicroCtx(hist = [], role) {
  const last = hist.filter(m => m.role === role).slice(-3);
  return last.map(m => `- (${m.role === 'owner' ? 'A' : 'B'}:${label(m.lang)}) ${m.text}`).join('\n');
}

function buildSystemPrompt(from, to, ctx) {
  const textingHint = `
When register is casual, prefer widely-understood texting abbreviations for ${label(to)}.
Examples (illustrative, do not overuse or force):
- Korean: ㅋㅋ/ㅎㅎ, ㅇㅋ(OK), ㄱㄱ(go), ㄴㄴ(no), ㅠㅠ/ㅜㅜ
- English: lol, brb, btw, idk, u/ur, thx/ty
- Spanish: q/xq (que/porque), jajaja, tqm, xfa (porfa)
- French: stp/svp, bjr/slt, mdr, pk
- German: k, lg, btw
Keep readability. If input is polite/formal (honorifics, titles), avoid abbreviations entirely.
Never use offensive or regionally-obscure slang. Preserve names, numbers, emojis, and punctuation rhythm.`;

  return [
    `You are a world-class real-time conversational translator.`,
    `Prioritize STYLE PRESERVATION (tone/register, politeness level, slang) over long-term memory.`,
    ctx ? `Speaker style hints (recent lines):\n${ctx}` : `Speaker style hints: (none)`,
    `Translate from ${label(from)} to ${label(to)}.`,
    textingHint,
    `Do not summarize, omit, or add meaning. Return ONLY the translation text.`,
  ].join('\n');
}

async function fastTranslate(text, from, to, ctx) {
  if (!openai || !text || !to || to === 'auto' || from === to) return text;
  const sys = buildSystemPrompt(from, to, ctx);
  const r = await openai.chat.completions.create({
    model: 'gpt-4o-mini',
    temperature: 0.2,
    messages: [
      { role: 'system', content: sys },
      { role: 'user', content: text },
    ],
  });
  return r.choices?.[0]?.message?.content?.trim() || text;
}

async function hqTranslate(text, from, to, ctx) {
  if (!openai || !text || !to || to === 'auto' || from === to) return text;
  const sys = buildSystemPrompt(from, to, ctx) + `\nPolish wording to native fluency *without changing tone or meaning*.`;
  const r = await openai.chat.completions.create({
    model: 'gpt-4o',
    temperature: 0.2,
    messages: [
      { role: 'system', content: sys },
      { role: 'user', content: text },
    ],
  });
  return r.choices?.[0]?.message?.content?.trim() || text;
}

async function emitRoutes(roomId) {
  const meta = ROOMS.get(roomId) || {};
  const sockets = await io.in(roomId).fetchSockets();
  for (const s of sockets) {
    const rec = SOCKET_ROLES.get(s.id);
    if (!rec) continue;
    const fromCode = rec.role === 'owner' ? meta.ownerLang : meta.guestLang;
    const toCode   = rec.role === 'owner' ? meta.guestLang : meta.ownerLang;
    io.to(s.id).emit('route-ready', {
      from: label(fromCode) || 'auto',
      to:   label(toCode)   || 'auto',
      fromCode: fromCode || 'auto',
      toCode:   toCode   || 'auto',
    });
  }
}

io.on('connection', (socket) => {
  console.log('🟢 New client connected:', socket.id);

  // ======================================================
  // ✅ 호스트 방 생성 이벤트 (클라이언트에서 roomId 지정)
  // ======================================================
  socket.on("create-room", ({ roomId, fromLang }) => {
    if (!roomId) return;
    socket.join(roomId);
    socket.roomId = roomId; // 소켓에 roomId 연결

    // 방 메타데이터와 호스트 역할 설정
    const hostLangCode = mapLang(fromLang);
    ROOMS.set(roomId, { ownerLang: hostLangCode, guestLang: "auto" });
    SOCKET_ROLES.set(socket.id, { role: "owner" });

    console.log(`🏠 Host ${socket.id} created room: ${roomId} with language '${hostLangCode}'`);
  });

  socket.on('joinRoom', (roomId) => {
    socket.join(roomId);
    socket.roomId = roomId;
    console.log(`👥 ${socket.id} joined room ${roomId}`);
  });

  // --- 요청하신 내용으로 수정된 부분 (join 핸들러) ---
  socket.on("join", ({ roomId, fromLang, nick, participantId }) => {
    if (!roomId || !participantId) return;
    socket.join(roomId);
    socket.roomId = roomId;
    console.log(`[JOIN] ${socket.id} (pid: ${participantId}) -> ${roomId}`);

    socket.to(roomId).emit("guest:joined", {
      roomId,
      socketId: socket.id,
      lang: fromLang || "auto",
      nick: nick || ""
    });

    // ✅ 수정: 내 participantId와 다른 메시지만 필터링하여 복원
    const missed = (messageBuffer[roomId] || []).filter(
      (m) => m.senderPid !== participantId
    );

    if (missed.length > 0) {
      socket.emit("recent-messages", missed);
      console.log(`📩 Restored ${missed.length} messages for pid ${participantId} in ${roomId}`);
    }

    // ✅ 방이 완전히 비면 버퍼 자동 삭제 (무기록 유지)
    setTimeout(() => {
      const room = io.sockets.adapter.rooms.get(roomId);
      if (!room || room.size === 0) {
        delete messageBuffer[roomId];
        console.log(`🧹 Cleared buffer for room ${roomId}`);
      }
    }, 5000);
  });
  // --- 수정 완료 ---

  socket.on('register', ({ role, lang }) => {
    if (!socket.roomId) return;
    const meta = ensureRoomMeta(socket.roomId);
    SOCKET_ROLES.set(socket.id, { role: role === 'owner' ? 'owner' : 'guest' });

    const code = mapLang(lang || 'en');

    if (role === 'owner')  meta.ownerLang = code || 'auto';
    else                   meta.guestLang = code || 'auto';

    ROOMS.set(socket.roomId, meta);
    emitRoutes(socket.roomId);
    console.log(`📝 room=${socket.roomId} role=${role} lang=${code} ->`, meta);
  });

  socket.on('set-lang', ({ roomId, lang }) => {
    if (!roomId || !lang) return;
    const meta = ensureRoomMeta(roomId);
    const rec  = SOCKET_ROLES.get(socket.id) || { role: !meta.ownerLang ? 'owner' : 'guest' };
    SOCKET_ROLES.set(socket.id, rec);
  
    if (rec.role === 'owner') meta.ownerLang = lang;
    else meta.guestLang = lang;
  
    ROOMS.set(roomId, meta);
    emitRoutes(roomId);
  });

  // --- 요청하신 내용으로 수정된 부분 (send-message 핸들러) ---
  socket.on('send-message', async ({ roomId, message, participantId }) => {
    if (!roomId || !message || !participantId) return;
    const { id, text } = message;
    const meta = ROOMS.get(roomId);
    if (!meta) return;
  
    dlog(`[chat] pid=${participantId} → room=${roomId}: ${text}`);
    
    // 버퍼에 senderPid 포함하여 저장
    if (!messageBuffer[roomId]) messageBuffer[roomId] = [];
    messageBuffer[roomId].push({
      id: id,
      text: text,
      senderPid: participantId,
      time: Date.now(),
    });
    if (messageBuffer[roomId].length > 200) messageBuffer[roomId].shift();
  
    const rec = SOCKET_ROLES.get(socket.id) || {};
    const fromLang = rec.role === 'owner' ? meta.ownerLang : meta.guestLang;
    const toLang   = rec.role === 'owner' ? meta.guestLang : meta.ownerLang;
  
    let draft = text;
    try {
      draft = await fastTranslate(text, fromLang, toLang, '');
    } catch (e) {
      console.warn('[fastTranslate]', e.message);
    }
  
    // senderPid 포함, 자신 제외 브로드캐스트
    socket.to(roomId).emit('receive-message', {
      id,
      senderPid: participantId,
      originalText: text,
      translatedText: draft,
      isDraft: true,
      at: Date.now(),
    });

    // ✅ 수정: 자신 제외 알림 (상대방만)
    socket.to(roomId).emit("notify", {
      title: "새 메시지",
      body: text.substring(0, 50) || "메시지가 도착했습니다.",
    });

    // ✅ 삭제: FCM 호출 부분 제거됨
  
    let hq = draft;
    try {
      hq = await hqTranslate(text, fromLang, toLang, '');
    } catch (e) {
        console.warn('[hqTranslate]', e.message);
    }
    
    // senderPid 포함, 자신 제외 브로드캐스트
    socket.to(roomId).emit('revise-message', {
        id,
        senderPid: participantId,
        translatedText: hq,
        isDraft: false,
    });
  });
  // --- 수정 완료 ---

  socket.on('disconnect', (reason) => {
    const roomId = socket.roomId;
    console.log(`🔴 ${socket.id} disconnected from room ${roomId} (${reason})`);
    
    if (!roomId) return;
    SOCKET_ROLES.delete(socket.id);
    const roomSockets = io.sockets.adapter.rooms.get(roomId);
    const remaining = roomSockets ? roomSockets.size : 0;

    if (remaining === 0) {
      ROOMS.delete(roomId);
      console.log(`💨 Room ${roomId} removed (no sockets left)`);
    } else {
      console.log(`👤 Room ${roomId} has ${remaining} socket(s) remaining`);
    }
  });

  socket.on('reconnect', () => {
    if (socket.roomId) {
      socket.join(socket.roomId);
      console.log(`🔁 ${socket.id} rejoined room ${socket.roomId}`);
    }
  });

  socket.conn.on("close", (reason) => {
    console.log(`⚠️ Socket connection closed (${reason}), waiting for reconnect...`);
  });
});

async function sniff(buffer) {
  try {
    const {fileTypeFromBuffer} = await import('file-type');
    return fileTypeFromBuffer(buffer);
  } catch (e) {
    console.warn("File type sniffing failed:", e.message);
    return null;
  }
}

function bufferToWav(buffer) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    const stream = require("stream").Readable.from(buffer);
    let cmd;

    const timeout = setTimeout(() => {
        if(cmd) cmd.kill('SIGKILL');
        reject(new Error("ffmpeg timeout"));
    }, 3000);

    cmd = new Ffmpeg(stream)
      .inputFormat("webm")
      .audioCodec("pcm_s16le")
      .format("wav")
      .on("error", (err) => {
        clearTimeout(timeout);
        reject(err);
      })
      .on("end", () => {
        clearTimeout(timeout);
        resolve(Buffer.concat(chunks));
      });
    
    cmd.pipe().on("data", c => chunks.push(c));
  });
}

