// server/stt_google_stream.js (CJS)
const { SpeechClient } = require("@google-cloud/speech");

function bindGoogleSTT(io) {
  io.on("connection", (s) => {
    let sttStream = null;
    const client = new SpeechClient(); // GOOGLE_APPLICATION_CREDENTIALS로 인증

    function startStream({ lang = "ko-KR", sampleRateHz = 16000 } = {}) {
      if (sttStream) { try { sttStream.end(); } catch {} sttStream = null; }

      sttStream = client
        .streamingRecognize({
          config: {
            encoding: "LINEAR16",
            sampleRateHertz: sampleRateHz,
            languageCode: lang,
            enableAutomaticPunctuation: true,
            model: "latest_short",
          },
          interimResults: true,
        })
        .on("error", () => { /* 필요시 로깅 */ })
        .on("data", (data) => {
          const r = data.results?.[0];
          const alt = r?.alternatives?.[0];
          if (alt?.transcript) {
            s.emit("stt:result", { text: alt.transcript, final: !!r?.isFinal });
          }
        });

      s.emit("stt:ready");
    }

    s.on("stt:start", (opts) => startStream(opts));
    s.on("stt:audio", ({ chunkBase64 }) => {
      if (sttStream && chunkBase64) {
        sttStream.write({ audioContent: Buffer.from(chunkBase64, "base64") });
      }
    });
    s.on("stt:stop", () => {
      if (sttStream) { try { sttStream.end(); } catch {} sttStream = null; }
    });
    s.on("disconnect", () => {
      if (sttStream) { try { sttStream.end(); } catch {} sttStream = null; }
    });
  });
}

module.exports = { bindGoogleSTT };

const { OAuth2Client } = require('google-auth-library');
const jwt = require('jsonwebtoken');

module.exports = function attachGoogleAuth(app) {
  // JWT_SECRET 환경 변수 존재 여부 확인
  if (!process.env.JWT_SECRET) {
    console.error('SERVER_MISCONFIG: JWT_SECRET environment variable is not set for Google authentication.');
    // 이 미들웨어는 Express 앱에 등록되므로, 직접 응답을 보냅니다.
    app.use('/auth/google', (req, res) => {
      res.status(500).send('SERVER_MISCONFIG:JWT_SECRET');
    });
    app.use('/auth/google/callback', (req, res) => {
      res.status(500).send('SERVER_MISCONFIG:JWT_SECRET');
    });
    return; // JWT_SECRET이 없으면 더 이상 라우트 설정을 진행하지 않습니다.
  }

  const client = new OAuth2Client({
    clientId: process.env.GOOGLE_CLIENT_ID,
    clientSecret: process.env.GOOGLE_CLIENT_SECRET,
    redirectUri: process.env.GOOGLE_CALLBACK_URL,
  });

  // 1) 구글로 리다이렉트
  app.get('/auth/google', (req, res) => {
    const next = req.query.next || '/';
    const url = client.generateAuthUrl({
      access_type: 'offline',
      scope: ['openid', 'email', 'profile'],
      prompt: 'consent',
      state: Buffer.from(JSON.stringify({ next })).toString('base64url'),
    });
    res.redirect(url);
  });

  // 2) 콜백 → JWT 발급 → next로 이동
  app.get('/auth/google/callback', async (req, res) => {
    try {
      const { code, state } = req.query;
      const { tokens } = await client.getToken(code);
      const idToken = tokens.id_token;
      if (!idToken) return res.status(400).send('GOOGLE_NO_IDTOKEN');

      // ID 토큰에서 사용자 정보 추출
      const ticket = await client.verifyIdToken({
        idToken,
        audience: process.env.GOOGLE_CLIENT_ID,
      });
      const payload = ticket.getPayload();
      const sub = `google:${payload.sub}`;
      const profile = {
        id: sub,
        displayName: payload.name || 'Google User',
        photoURL: payload.picture || '',
        email: payload.email || '',
        provider: 'google',
      };

      // JWT 발급 (30일)
      const appJwt = jwt.sign(
        { sub: profile.id, name: profile.displayName, pic: profile.photoURL, p: profile.provider },
        process.env.JWT_SECRET,
        { expiresIn: '30d' }
      );

      // httpOnly 쿠키 + 로컬에서도 동작하도록 sameSite Lax
      res.cookie('token', appJwt, {
        httpOnly: true,
        secure: true,          // 프로덕션(https) 기준
        sameSite: 'lax',
        maxAge: 30 * 24 * 60 * 60 * 1000,
      });

      let next = '/';
      if (state) {
        try { next = JSON.parse(Buffer.from(state, 'base64url').toString()).next || next; } catch {}
      }
      return res.redirect(next);
    } catch (e) {
      console.error('google_callback_error', e);
      return res.status(500).send('GOOGLE_CALLBACK_ERROR');
    }
  });
};

const axios = require('axios');
const jwt = require('jsonwebtoken');

module.exports = function attachKakaoAuth(app) {
  // JWT_SECRET 환경 변수 존재 여부 확인
  if (!process.env.JWT_SECRET) {
    console.error('SERVER_MISCONFIG: JWT_SECRET environment variable is not set for Kakao authentication.');
    // 이 미들웨어는 Express 앱에 등록되므로, 직접 응답을 보냅니다.
    app.use('/auth/kakao', (req, res) => {
      res.status(500).send('SERVER_MISCONFIG:JWT_SECRET');
    });
    app.use('/auth/kakao/callback', (req, res) => {
      res.status(500).send('SERVER_MISCONFIG:JWT_SECRET');
    });
    return; // JWT_SECRET이 없으면 더 이상 라우트 설정을 진행하지 않습니다.
  }

  // 1) 카카오로 리다이렉트
  app.get('/auth/kakao', (req, res) => {
    const next = req.query.next || '/';
    const params = new URLSearchParams({
      client_id: process.env.KAKAO_CLIENT_ID,
      redirect_uri: process.env.KAKAO_CALLBACK_URL,
      response_type: 'code',
      state: Buffer.from(JSON.stringify({ next })).toString('base64url'),
    });
    res.redirect(`https://kauth.kakao.com/oauth/authorize?${params.toString()}`);
  });

  // 2) 콜백 → 토큰 교환 → 사용자 조회 → JWT 발급 → next로 이동
  app.get('/auth/kakao/callback', async (req, res) => {
    try {
      const { code, state } = req.query;

      // 액세스 토큰
      const tokenRes = await axios.post('https://kauth.kakao.com/oauth/token', new URLSearchParams({
        grant_type: 'authorization_code',
        client_id: process.env.KAKAO_CLIENT_ID,
        client_secret: process.env.KAKAO_CLIENT_SECRET, // 사용 설정된 경우 필수
        redirect_uri: process.env.KAKAO_CALLBACK_URL,
        code,
      }), { headers: { 'Content-Type': 'application/x-www-form-urlencoded' } });

      const accessToken = tokenRes.data.access_token;
      if (!accessToken) return res.status(400).send('KAKAO_NO_TOKEN');

      // 사용자 정보
      const meRes = await axios.get('https://kapi.kakao.com/v2/user/me', {
        headers: { Authorization: `Bearer ${accessToken}` }
      });
      const kuser = meRes.data;
      const sub = `kakao:${kuser.id}`;
      const profile = {
        id: sub,
        displayName: kuser.properties?.nickname || 'Kakao User',
        photoURL: kuser.properties?.profile_image || '',
        provider: 'kakao',
      };

      // JWT (30일)
      const appJwt = require('jsonwebtoken').sign(
        { sub: profile.id, name: profile.displayName, pic: profile.photoURL, p: profile.provider },
        process.env.JWT_SECRET,
        { expiresIn: '30d' }
      );

      res.cookie('token', appJwt, {
        httpOnly: true,
        secure: true,
        sameSite: 'lax',
        maxAge: 30 * 24 * 60 * 60 * 1000,
      });

      let next = '/';
      if (state) {
        try { next = JSON.parse(Buffer.from(state, 'base64url').toString()).next || next; } catch {}
      }
      return res.redirect(next);
    } catch (e) {
      console.error('kakao_callback_error', e?.response?.data || e);
      return res.status(500).send('KAKAO_CALLBACK_ERROR');
    }
  });
};

// server/socket/message-handler.js (새 파일)
import OpenAI from "openai";

const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

// 아주 단순한 번역 헬퍼 (형님이 쓰는 한-영 위주, 필요시 확대)
async function translate(text, targetLang = "ko") {
  // gpt-4o-mini 번역 1패스
  const prompt = `Translate to ${targetLang}. Only translation: ${text}`;
  const res = await openai.chat.completions.create({
    model: "gpt-4o-mini",
    messages: [{ role: "user", content: prompt }],
    temperature: 0.2,
  });
  return res.choices[0]?.message?.content?.trim() || text;
}

export function attachMessageHandler(io) {
  io.on("connection", (socket) => {
    socket.on("join", ({ roomId }) => {
      if (roomId) socket.join(roomId);
    });

    socket.on("message", async (msg) => {
      try {
        const { id, roomId, text, srcLang, targetLang } = msg;
        if (!roomId || !text) return;

        // 호스트/게스트 상대방이 보는 언어로 서버에서 번역
        // (기존 방에 저장된 상대 언어가 있으면 그걸 쓰고, 없으면 msg.targetLang 사용)
        const toLang = targetLang || "en";
        const translatedText = await translate(text, toLang);

        const payload = {
          ...msg,
          translatedText,
          ts: Date.now(),
        };

        // 방 전체에 브로드캐스트(자기 자신 포함 필요 시 바꾸세요)
        io.to(roomId).emit("message", payload);
      } catch (e) {
        console.error("[message.translate]", e.message);
      }
    });

    socket.on("readAll", ({ roomId, lastTs }) => {
      if (!roomId || !lastTs) return;
      socket.to(roomId).emit("peerRead", { lastTs });
    });
  });
}

