import { io } from "socket.io-client";

// ---- 설정 (기존 하드코딩 X) ----
const WS_ORIGIN =
  (window.location.hostname && window.location.protocol.startsWith("https"))
    ? `wss://${window.location.host}`
    : `http://127.0.0.1:3174`; // 로컬 테스트용
const WS_PATH = "/socket.io"; // 바꾸지 마세요

// ---- 소켓 초기화 ----
export const socket = io(WS_ORIGIN, {
  path: WS_PATH,
  transports: ["websocket"],
  withCredentials: false,
  autoConnect: true,
});

// ---- 세션 상태 ----
window.__CURRENT_ROOM_ID__ = window.__CURRENT_ROOM_ID__ || null;
window.__LANG__ = window.__LANG__ || "ko";
window.__ROLE__ = window.__ROLE__ || "host";

// ---- 가벼운 로컬 큐(백그라운드 중 수신/번역 누락 방지) ----
const PENDING_KEY = "mro_pending_msgs_v1";
const getQueue = () => JSON.parse(localStorage.getItem(PENDING_KEY) || "[]");
const setQueue = (q) => localStorage.setItem(PENDING_KEY, JSON.stringify(q));

// 수신 → 로컬 저장 → 화면 반영
socket.on("message", (msg) => {
  // 서버가 이미 번역을 붙여줌(아래 서버 패치 참고: translatedText)
  const safe = { ...msg, ts: msg.ts || Date.now() };
  const q = getQueue();
  q.push(safe);
  setQueue(q);

  // 화면에 즉시 반영하는 기존 함수만 호출 (UI 코드 손대지 않음)
  if (window.appendIncomingMessage) {
    window.appendIncomingMessage(safe);
  }

  // 탭이 숨김이면 가벼운 알림
  if (document.hidden) {
    if (navigator.vibrate) navigator.vibrate(30);
    document.title = "● 새 메시지 | Mr.O";
  }
});

// 읽음 처리(있을 때만)
export function markAllRead() {
  document.title = "Mr.O";
  const q = getQueue();
  const roomId = window.__CURRENT_ROOM_ID__;
  if (q.length && roomId) {
    socket.emit("readAll", { roomId, lastTs: q[q.length - 1].ts });
  }
}

// ---- 탭 내려갔다 올라올 때 재접속/재합류 ----
document.addEventListener("visibilitychange", () => {
  if (document.visibilityState === "visible") {
    markAllRead();
    if (socket && !socket.connected) {
      socket.connect();
    }
    if (window.__CURRENT_ROOM_ID__ && window.__LANG__ && window.__ROLE__) {
      socket.emit("join", {
        roomId: window.__CURRENT_ROOM_ID__,
        lang: window.__LANG__,
        role: window.__ROLE__,
      });

      // ✅ 요청하신 줄 추가
      socket.emit("refresh-lang-map", {
        roomId: window.__CURRENT_ROOM_ID__,
        lang: window.__LANG__,
        role: window.__ROLE__,
      });
    }

    // --- ⬇️ 형님이 요청하신 "ChatGPT" 코드 추가 (visibilitychange 내부) ⬇️ ---
    // 방 복구 보장 (호스트가 늦게 들어올 경우 자동 생성 요청)
    if (window.__ROLE__ === "owner") {
      socket.emit("join", {
        roomId: window.__CURRENT_ROOM_ID__,
        lang: window.__LANG__,
        role: "owner",
      });
      socket.emit("refresh-lang-map", {
        roomId: window.__CURRENT_ROOM_ID__,
        lang: window.__LANG__,
        role: "owner",
      });
      console.log("[socket] host rejoined room:", window.__CURRENT_ROOM_ID__);
    }
    // --- ⬆️ 코드 추가 완료 ⬆️ ---
  }
});

// ---- 방 입장(기존 로직 그대로 호출만 바인딩) ----
export function joinRoom({ roomId, lang, role }) {
  window.__CURRENT_ROOM_ID__ = roomId;
  window.__LANG__ = lang || "ko";
  window.__ROLE__ = role || "host";
  socket.emit("join", { roomId, lang: window.__LANG__, role: window.__ROLE__ });
}

// ---- 메시지 전송(중복/유실 방지용 ID) ----
export function sendMessage({ roomId, text, srcLang }) {
  const id = `${Date.now()}-${Math.random().toString(16).slice(2)}`;
  socket.emit("message", { id, roomId, text, srcLang: srcLang || window.__LANG__ });
}
