import React, { useEffect, useRef, useState } from "react";
import MicButton from "./MicButton";

const ChatInput = ({ onSend, onMicResult }) => {
  const [value, setValue] = useState("");
  const [isComposing, setIsComposing] = useState(false);
  const [listening, setListening] = useState(false);
  const taRef = useRef(null);

  const canSend = value.trim().length > 0;

  // textarea 자동 높이
  const autosize = () => {
    const ta = taRef.current;
    if (!ta) return;
    ta.style.height = "0px";
    const h = Math.min(ta.scrollHeight, 160); // 최대 약 6줄
    ta.style.height = h + "px";
  };
  useEffect(() => { autosize(); }, [value]);

  // 전역 이벤트로 MicButton의 시작/종료 신호 수신
  useEffect(() => {
    const onStart = () => setListening(true);
    const onStop = () => setListening(false);
    window.addEventListener("mro:mic:start", onStart);
    window.addEventListener("mro:mic:stop", onStop);
    return () => {
      window.removeEventListener("mro:mic:start", onStart);
      window.removeEventListener("mro:mic:stop", onStop);
    };
  }, []);

  const doSend = () => {
    if (!canSend) return;
    const text = value.trim();
    setValue("");
    onSend && onSend(text);
  };

  const onKeyDown = (e) => {
    if (isComposing) return;
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      doSend();
    }
  };

  return (
    <div className="sticky bottom-0 z-10 border-t border-gray-200 bg-white/95 backdrop-blur supports-[backdrop-filter]:bg-white/80">
      {/* 웨이브 애니메이션 키프레임 (컴포넌트 내부에 캡슐화) */}
      <style>{`
        @keyframes mroWave {
          0%, 100% { transform: scaleY(0.3); opacity: .7; }
          50% { transform: scaleY(1); opacity: 1; }
        }
      `}</style>

      <div className="mx-auto max-w-screen-sm px-3 py-2">
        <div className="flex items-end gap-2">
          {/* 마이크 버튼: 기존 onTextResult 연결 유지 */}
          <MicButton
            onTextResult={(r) => onMicResult && onMicResult(r.text)}
          />

          {/* 입력영역 */}
          <div className="flex-1 min-w-0">
            <div className="rounded-2xl border border-gray-300 bg-white shadow-sm px-3 py-2 focus-within:ring-2 focus-within:ring-blue-500/30">
              {/* 듣는 중이면 입력창 대신 웨이브 표시 */}
              {listening ? (
                <div className="h-6 flex items-end gap-1 py-1">
                  {[0,1,2,3,4].map((i) => (
                    <span
                      key={i}
                      style={{
                        animation: "mroWave 1.1s ease-in-out infinite",
                        animationDelay: `${i * 0.12}s`,
                        transformOrigin: "center bottom"
                      }}
                      className="w-[3px] h-4 bg-blue-600 rounded-full inline-block"
                    />
                  ))}
                </div>
              ) : (
                <textarea
                  ref={taRef}
                  className="w-full resize-none outline-none placeholder-gray-400 text-[15px] leading-6"
                  rows={1}
                  maxLength={4000}
                  placeholder="메시지를 입력하세요…"
                  value={value}
                  onChange={(e) => setValue(e.target.value)}
                  onKeyDown={onKeyDown}
                  onCompositionStart={() => setIsComposing(true)}
                  onCompositionEnd={() => setIsComposing(false)}
                  aria-label="메시지 입력"
                />
              )}

              <div className="flex justify-end">
                <button
                  type="button"
                  onClick={doSend}
                  disabled={!canSend}
                  className={`mt-2 inline-flex items-center rounded-xl px-3 py-1.5 text-sm font-medium transition
                    ${canSend ? "bg-blue-600 text-white hover:bg-blue-700" : "bg-gray-200 text-gray-500 cursor-not-allowed"}
                  `}
                  aria-label="전송"
                >
                  전송
                </button>
              </div>
            </div>
            {/* iOS 안전영역 */}
            <div style={{ paddingBottom: "env(safe-area-inset-bottom, 0px)" }} />
          </div>
        </div>
      </div>
    </div>
  );
};

