// 토큰 단위 즉시 반복(단어/구/문장)을 강제로 1회로 압축
function dedupeRepeatTokens(s) {
  if (!s) return s;

  // 단어/숫자/한글 + 구두점 + 기타 단일문자 토큰화
  let tokens;
  try {
    tokens = s.match(/[\p{L}\p{N}’']+|[.,!?;:。！？、，]+|\S/gu) || [s];
  } catch {
    tokens = s.match(/[A-Za-z0-9’']+|[가-힣]+|[.,!?;:。！？、，]+|\S/g) || [s];
  }

  const out = [];
  let i = 0;
  while (i < tokens.length) {
    const remain = tokens.length - i;
    const maxW = Math.min(12, Math.floor(remain / 2));
    let wFound = 0;

    for (let w = maxW; w >= 1; w--) {
      let same = true;
      for (let k = 0; k < w; k++) {
        if (tokens[i + k] !== tokens[i + w + k]) { same = false; break; }
      }
      if (same) { wFound = w; break; }
    }

    if (wFound > 0) {
      for (let k = 0; k < wFound; k++) out.push(tokens[i + k]);
      i += wFound;
      while (i + wFound <= tokens.length) {
        let same = true;
        for (let k = 0; k < wFound; k++) {
          if (tokens[i + k] !== out[out.length - wFound + k]) { same = false; break; }
        }
        if (!same) break;
        i += wFound;
      }
    } else {
      out.push(tokens[i]);
      i++;
    }
  }

  let s2 = "";
  for (let t = 0; t < out.length; t++) {
    const cur = out[t];
    const prev = out[t - 1] || "";
    const isPunct = /[.,!?;:。！？、，]/.test(cur);
    const needSpace = t > 0 && !isPunct && !/[([{"'@#$]/.test(cur) && !/[-/]/.test(prev) && !/[([{"'@#$]/.test(prev);
    s2 += (needSpace ? " " : "") + cur;
  }
  return s2.replace(/\s+([,;:])/g, "$1");
}

function dedupeRepeats(s) {
  if (!s) return s;
  const parts = s.split(/(?<=[.!?。！？])\s+/u);
  const out = [];
  let last = "";
  for (const p of parts) {
    const seg = p.trim();
    if (!seg) continue;
    const norm = seg.replace(/\s+/g, " ").toLowerCase();
    if (norm === last) continue;
    out.push(seg);
    last = norm;
  }

  const result = out.join(" ");
  return dedupeRepeatTokens(result);
}

export default function ChatScreen() {
  const { roomId } = useParams();
  const navigate = useNavigate();
  const location = useLocation();

  const pidKey = `mro.pid.${roomId}`;
  const [participantId] = useState(() => {
    let id = localStorage.getItem(pidKey);
    if (!id) {
      id = (crypto?.randomUUID?.() || Math.random().toString(36).slice(2));
      localStorage.setItem(pidKey, id);
    }
    return id;
  });

  const [fromLang, setFromLang] = useState(
    location.state?.fromLang || localStorage.getItem("myLang") || "ko"
  );
  const [myNick, setMyNick] = useState(
    location.state?.myNick || localStorage.getItem("myNick") || ""
  );

  const [messages, setMessages] = useState([]);
  const [inputText, setInputText] = useState("");
  const [routeInfo, setRouteInfo] = useState(null);
  const [peers, setPeers] = useState({ me: null, other: null });
  const myNickRef = useRef(myNick);
  const otherRef  = useRef(peers.other);

  useEffect(() => { myNickRef.current = myNick; }, [myNick]);
  useEffect(() => { otherRef.current  = peers.other; }, [peers.other]);

  const [micListening, setMicListening] = useState(false);
  const [interimText, setInterimText] = useState("");
  const micBufferRef = useRef("");     // 마이크 누른 동안 누적 텍스트
  const micUserOnRef = useRef(false);  // 내가 버튼으로 켰는지 여부

  const textareaRef = useRef(null);
  const sendingRef = useRef(false);
  const messagesEndRef = useRef(null);
  const pendingIdsRef = useRef(new Set());
  const lastByIdRef    = useRef(new Map());

  const wakeLockRef = useRef(null);

  const autosize = () => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = Math.min(el.scrollHeight, 200) + "px";
  };
  const resetHeight = () => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "40px";
  };

  useEffect(() => {
    if (!roomId) return;
    socket.emit("join", { roomId, fromLang, nick: myNick || undefined, participantId });
    setPeers((p) => ({ ...p, me: { nick: myNick || "", lang: fromLang } }));
  }, [roomId, fromLang, myNick, participantId]);

  useEffect(() => {
    const onSttPartial = ({ id, text }) => {
      if (!text) return;
      setMessages(prev => {
        const i = prev.findIndex(m => m.id === id);
        if (i === -1) {
          return [...prev, { id: id || uuidv4(), text, mine: false, nick: peers.other?.nick || "guest" }];
        } else {
          const next = [...prev];
          next[i] = { ...next[i], text };
          return next;
        }
      });
    };

    const onSttFinal = ({ id, text }) => {
      if (!text) return;
      setMessages(prev => prev.map(m => (m.id === id ? { ...m, text } : m)));
    };

    socket.on("stt_partial", onSttPartial);
    socket.on("stt_final", onSttFinal);

    return () => {
      socket.off("stt_partial", onSttPartial);
      socket.off("stt_final", onSttFinal);
    };
  }, [peers.other]);

  useEffect(() => {
    if ("Notification" in window && Notification.permission === "default") {
      Notification.requestPermission().catch(() => {});
    }
  }, []);

  useEffect(() => {
    const onNotify = (p) => {
      try {
        if (typeof Notification !== "undefined" && Notification.permission === "granted") {
          new Notification(p?.title || "Mr.O", { body: p?.body || "" });
        }
      } catch(e) { /* no-op */ }
      if (navigator?.vibrate) navigator.vibrate([120,60,120]);
    };
    socket.on("notify", onNotify);
    return () => socket.off("notify", onNotify);
  }, []);

  useEffect(() => {
    const onLangUpdate = (langs) => {
      try {
        if (setOwnerLang) setOwnerLang(langs.ownerLang);
        if (setGuestLang) setGuestLang(langs.guestLang);
      } catch(_) {}
    };
    socket.on("lang-update", onLangUpdate);
    return () => socket.off("lang-update", onLangUpdate);
  }, []);

  useEffect(() => {
    const onRouteReady = (payload) => {
      const { from, to } = payload || {};
      if (!from || !to) return;
      setRouteInfo({ from, to });
    };

    const onPresence = (payload) => {
      const users = (payload && payload.users) || [];
      const mine = myNickRef.current || "";
      const others = users.filter(u => u && u.nick !== mine);
      if (others[0]) {
        setPeers(p => ({ ...p, other: { nick: others[0].nick || "", lang: others[0].lang || "" } }));
      }
    };

    const onReceiveMessage = (payload) => {
      const { id, originalText, translatedText, isDraft, nick, senderId, senderPid } = payload || {};

      // ✅ participantId 기반 내 메시지 판별
      const isMine = senderPid && senderPid === participantId;

      if (isMine) {
        // 내 메시지는 이미 화면에 표시됨 → 알림 불필요
        if (translatedText && translatedText !== originalText) {
          setMessages(prev => prev.map(m => (m.id === id ? { ...m, text: translatedText } : m)));
        }
        if (!isDraft && id) pendingIdsRef.current.delete(id);
        return;
      }

      // 상대방 메시지 처리
      const incoming = dedupeRepeats(translatedText || originalText || "");
      if (!incoming) return;

      const msgId = id || uuidv4();
      setMessages(prev => [...prev, { id: msgId, text: incoming, mine: false }]);

      // ✅ 알림: 내 메시지 아님 + 백그라운드일 때만
      if (document.visibilityState === "hidden") {
        if ("serviceWorker" in navigator) {
          const sendToSW = (reg) => reg?.active?.postMessage({
            type: "SHOW_NOTIFICATION",
            payload: { title: "새 메시지", body: incoming.slice(0, 80) }
          });
          navigator.serviceWorker.controller
            ? navigator.serviceWorker.controller.postMessage({
                type: "SHOW_NOTIFICATION",
                payload: { title: "새 메시지", body: incoming.slice(0, 80) }
              })
            : navigator.serviceWorker.getRegistration().then(sendToSW);
        }
      }
    };

    const onReviseMessage = (payload) => {
      const { id, translatedText } = payload || {};
      if (!id || !translatedText) return;
      setMessages(prev => prev.map(m => (m.id === id ? { ...m, text: translatedText } : m)));
      pendingIdsRef.current.delete(id);
    };

    const onRecentMessages = (msgs) => {
      if (!Array.isArray(msgs) || !msgs.length) return;
      console.log("📩 복원 메시지 수신:", msgs.length);

      setMessages(prev => {
        const merged = [...prev];
        for (const m of msgs) {
          const text =
            m.text ||
            m.translatedText ||
            m.originalText ||
            "(내용 없음)";
          merged.push({
            id: m.id || crypto.randomUUID(),
            text,
            mine: (m.senderId === socket.id), // 내 것 표시는 하되…
            nick: m.nick || "guest",
          });
        }
        return merged;
      });
      // ✅ 복원에 대해서는 알림 없음 (중복/자기 알림 방지)
    };

    const onJoined = (payload) => {
      const { nick, lang } = payload || {};
      setPeers(p => ({ ...p, other: { nick: nick || "", lang: lang || "" } }));
      setMessages(prev => [...prev, { id: uuidv4(), text: "상대방이 입장했습니다.", system: true }]);
    };

    socket.on("route-ready", onRouteReady);
    socket.on("presence", onPresence);
    socket.on("receive-message", onReceiveMessage);
    socket.on("recent-messages", onRecentMessages);
    socket.on("revise-message", onReviseMessage);
    socket.on("user-joined", onJoined);

    return () => {
      socket.off("route-ready", onRouteReady);
      socket.off("presence", onPresence);
      socket.off("receive-message", onReviseMessage);
      socket.off("recent-messages", onRecentMessages);
      socket.off("revise-message", onReviseMessage);
      socket.off("user-joined", onJoined);
    };
  }, [myNick, peers.other]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages]);
  useEffect(() => { autosize(); }, []);

  useEffect(() => {
    const requestWakeLock = async () => {
      try {
        if ('wakeLock' in navigator) {
          wakeLockRef.current = await navigator.wakeLock.request('screen');
        }
      } catch (_) { /* 무시 */ }
    };
    
    requestWakeLock();
  
    const onVisibility = () => {
      if (document.visibilityState === 'visible') requestWakeLock();
    };
    document.addEventListener('visibilitychange', onVisibility);
  
    return () => {
      document.removeEventListener('visibilitychange', onVisibility);
      try { wakeLockRef.current?.release(); } catch (_) {}
    };
  }, []);

  useEffect(() => {
    const iv = setInterval(() => {
      if (roomId) {
        socket.emit('keepalive', { roomId, t: Date.now() });
      }
    }, 25000);
    return () => clearInterval(iv);
  }, [roomId]);
  
  useEffect(() => {
    if (!roomId) return;
  
    const rejoin = () => {
      const nick = myNickRef.current || undefined;
      socket.emit("join", { roomId, fromLang, nick, participantId });
      socket.emit("set-lang", { roomId, lang: fromLang });
    };
  
    const onConnect = () => rejoin();
    const onOnline  = () => { if (!socket.connected) socket.connect(); };
  
    socket.on("connect", onConnect);
    window.addEventListener("online", onOnline);
  
    if (socket.connected) rejoin();
  
    return () => {
      socket.off("connect", onConnect);
      window.removeEventListener("online", onOnline);
    };
  }, [roomId, fromLang, participantId]);

  const handleLeave = () => {
    socket.emit("manual-leave");
    socket.disconnect();
    navigate("/");
  };
  
  const addMessage = ({ id, role, text, type }) => {
    setMessages((prev) => [...prev, { id, text, mine: role === "me", nick: myNick || "" }]);
  };

  const onMicListeningChange = (listening) => {
    setMicListening(listening);
    if (!listening) {
      const raw = (micBufferRef.current || "").trim();
      const t = dedupeRepeats(raw);
      setInterimText("");
      if (t) {
        const last = lastByIdRef.current.get("micLastSent");
        if (last !== t) {
          lastByIdRef.current.set("micLastSent", t);
          const msgId = uuidv4();
          pendingIdsRef.current.add(msgId);
          addMessage({ id: msgId, role: "me", text: t, type: "final" });
          socket.emit("send-message", { roomId, message: { id: msgId, text: t }, participantId });
        }
      }
      micBufferRef.current = "";
    }
  };

  const handleMicInterim = (text) => {
    const t = (text || "").trim();
    setInterimText(t);
    micBufferRef.current = t;
  };

  const handleMicFinal = (text) => {
    if (!text || !text.trim()) return;
    const t = text.trim();
    setInterimText("");
    micBufferRef.current = t;
    if (!micListening) {
      if (lastByIdRef.current.get("micLastSent") !== t) {
        lastByIdRef.current.set("micLastSent", t);
        const msgId = uuidv4();
        pendingIdsRef.current.add(msgId);
        addMessage({ id: msgId, role: "me", text: t, type: "final" });
        socket.emit("send-message", { roomId, message: { id: msgId, text: t }, participantId });
      }
      micBufferRef.current = "";
    }
  };

  const canSend = inputText.trim().length > 0;

  return (
    <div className="relative">
      <div className="h-screen w-screen flex flex-col max-w-screen-sm mx-auto bg-white text-black">
        <div className="fixed top-0 left-0 right-0 px-4 pt-4 bg-white z-10 flex items-center justify-between gap-2 max-w-screen-sm mx-auto">
          <div className="text-sm text-gray-600">
            {routeInfo ? (
              <span className="px-2 py-1 rounded-lg bg-green-100 text-green-700 self-start">
                {routeInfo.from} → {routeInfo.to}
              </span>
            ) : (
              <span className="px-2 py-1 rounded-lg bg-yellow-100 text-yellow-700 self-start">
                언어 경로 대기 중…
              </span>
            )}
          </div>
          <div className="flex items-center gap-2">
            <MicSelectBox />
            <button onClick={handleLeave} className="p-2 bg-red-100 rounded-full text-red-700 shadow-md" title="나가기">
              <LogOut size={20} />
            </button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto px-4 pt-[72px] pb-[88px]">
          {messages.map((m) => (
            <MessageBubble key={m.id} message={m} />
          ))}
          {interimText && (
            <div className={`mt-2 text-gray-400 text-sm flex items-start gap-2 max-w-[85%] break-words ml-auto`}>
              {interimText}
            </div>
          )}
          <div ref={messagesEndRef} />
        </div>

        <form
          className="fixed bottom-0 left-0 right-0 px-4 pb-4 bg-white z-10 max-w-screen-sm mx-auto flex gap-2 items-end"
          onSubmit={(e) => {
            e.preventDefault();
            if (!canSend) return;
            const msgId = uuidv4();
            pendingIdsRef.current.add(msgId);
            addMessage({ id: msgId, role: "me", text: inputText });
            socket.emit("send-message", { roomId, message: { id: msgId, text: inputText }, participantId });
            setInputText("");
            resetHeight();
          }}
        >
          <div className="relative flex-1">
            {micListening && (
              <div className="listening-wave"><span></span><span></span><span></span><span></span><span></span></div>
            )}

            <textarea
              ref={textareaRef}
              rows={1}
              className="w-full resize-none rounded-xl p-2 text-sm border border-gray-300 leading-6 max-h-[120px] overflow-y-auto"
              value={inputText}
              onChange={(e) => {
                setInputText(e.target.value);
                autosize();
              }}
              onKeyDown={(e) => {
                if (e.key === "Enter" && !e.shiftKey) {
                  e.preventDefault();
                  const msgId = uuidv4();
                  pendingIdsRef.current.add(msgId);
                  addMessage({ id: msgId, role: "me", text: inputText });
                  socket.emit("send-message", { roomId, message: { id: msgId, text: inputText }, participantId });
                  setInputText("");
                  resetHeight();
                }
              }}
              placeholder="메시지를 입력하세요..."
            />
          </div>

          <MicButton
            lang={fromLang}
            onListeningChange={onMicListeningChange}
            onInterim={handleMicInterim}
            onFinal={handleMicFinal}
          />

          <button type="submit" className="px-4 py-2 rounded-xl bg-blue-500 text-white text-sm z-20">Send</button>
        </form>
      </div>
      <InstallBanner />
    </div>
  );
}

