  const lastTextRef = useRef("");
  // ✅ 누적 본문(확정) + 진행 중(1개) + 직전 UI 반영 문자열
  const finalTextRef = useRef("");   // 확정 누적(전부)
  const interimRef   = useRef("");   // 현재 진행 중 1개
  const lastUiRef    = useRef("");   // onInterim으로 마지막 보낸 문자열

  const srRef = useRef(null);
  const mrRef = useRef(null);
  const mrStreamRef = useRef(null);
  const chunksRef = useRef([]);

  useEffect(() => {
    // 강제 스위치가 있으면 우선 (옵션): localStorage.setItem('asrMode','mr'|'sr'|'file')
    const forced = (typeof localStorage!=="undefined" && localStorage.getItem("asrMode")) || "";
    if (forced) { setMode(forced); return; }
    // 기본: 디바이스 무관, 지원되면 MR(서버 STT) 우선 → GPT 방식
    if (supportsMR) setMode("mr");
    else if (SR) setMode("sr");
    else setMode("file");
  }, [SR, supportsMR]);

  // 선호 장치: 사용자가 고른 deviceId가 있을 때만 사용, 기본은 'auto'
  const getPreferredDeviceId = async () => {
    const saved = (typeof localStorage!=="undefined" && localStorage.getItem("micDeviceId")) || "auto";
    if (!saved || saved === "auto") return undefined;
    try {
      const devs = await navigator.mediaDevices.enumerateDevices();
      const ok = devs.some(d => d.kind === "audioinput" && d.deviceId === saved);
      return ok ? saved : undefined;
    } catch { return undefined; }
  };

  const forceStopAll = () => {
    wantRef.current = false;
    try { if (srRef.current) { srRef.current.onend = null; srRef.current.onerror = null; srRef.current.stop?.(); srRef.current.abort?.(); srRef.current = null; } } catch {}
    try {
      if (mrRef.current?.state === "recording") mrRef.current.stop();
      if (mrStreamRef.current) { mrStreamRef.current.getTracks().forEach(t=>t.stop()); mrStreamRef.current=null; }
      mrRef.current = null;
    } catch {}
    setListening(false);
    onListeningChange?.(false);
    window.dispatchEvent(new Event("mro:mic:stop"));
    // ✅ 그래프 강제 리셋 (구형 기기 호환)
    window.dispatchEvent(new Event("mro:mic:level:reset"));
  };

  const startSR = () => {
    if (!SR) return false;

    try {
      if (srRef.current) {
        srRef.current.onend = null;
        srRef.current.onerror = null;
        srRef.current.stop?.();
        srRef.current.abort?.();
        srRef.current = null;
      }
    } catch {}

    const r = new SR();
    r.continuous = true;        // ✅ 침묵 구간 지나도 계속
    r.interimResults = true;    // ✅ 실시간 중간 결과
    r.maxAlternatives = 1;
    r.lang = toSpeechLocale(lang);
    // 새 세션 시작 시(버튼 누르고 처음 시작할 때)만 리셋
    finalTextRef.current = "";
    interimRef.current   = "";
    lastUiRef.current    = "";
    lastTextRef.current  = "";

    r.onstart = () => {
      setListening(true);
      onListeningChange?.(true);
      window.dispatchEvent(new Event("mro:mic:start"));
    };

    // ✅ 최종만 누적 + 진행 중 1개 + 경계 오버랩 제거
    const appendWithOverlap = (base, addition) => {
      const a = (base || "");
      const b = (addition || "");
      const max = Math.min(120, a.length, b.length);
      let k = 0;
      for (let t = max; t > 0; t--) {
        if (a.endsWith(b.slice(0, t))) { k = t; break; }
      }
      return a + b.slice(k);
    };

    r.onresult = (e) => {
      let interim = "";
      // 변경된 구간만 처리
      for (let i = e.resultIndex; i < e.results.length; i++) {
        const res = e.results[i];
        const t = (res[0]?.transcript || "").trim();
        if (!t) continue;
        if (res.isFinal) {
          // 최종 확정은 누적(경계 오버랩 제거)
          finalTextRef.current = appendWithOverlap(finalTextRef.current, t);
          interimRef.current = "";
        } else {
          interim = t; // 진행 중은 항상 1개만
          interimRef.current = interim;
        }
      }
      const space = finalTextRef.current && interimRef.current ? " " : "";
      const full = (finalTextRef.current + space + (interimRef.current || ""))
                    .replace(/\s+/g, " ").trim();
      // 같은 내용이면 UI 업데이트 생략(플리커/중복 방지)
      if (full !== lastUiRef.current) {
        lastUiRef.current = full;
        lastTextRef.current = full;
        onInterim?.(full); // 듣는 동안 UI에만 반영(전송 금지)
      }
    };
    
    // ✅ 크롬이 세션을 끊어도 듣기 상태면 즉시 재시작
    r.onend = () => {
      setListening(false);
      if (wantRef.current) {
        try { r.start(); } catch (_) {}
      } else {
        onListeningChange?.(false);
        window.dispatchEvent(new Event("mro:mic:stop"));
      }
    };

    r.onerror = (_e) => {
      // 에러 무시하고 재시작 시도
    };

    try { r.start(); srRef.current = r; return true; } catch { return false; }
  };

  const startMR = async () => {
    try {
      const devId = await getPreferredDeviceId(); // undefined면 Auto
      let stream;
      const base = {
        audio: {
          deviceId: devId ? { exact: devId } : undefined,
          channelCount: { ideal: 1 },
          sampleRate:   { ideal: 48000 },
          echoCancellation: false,
          noiseSuppression: false,
          autoGainControl:  false,
        },
      };
      try {
        stream = await navigator.mediaDevices.getUserMedia(base);
      } catch (e) {
        // 선택 장치가 사라졌거나 점유 중이면 장치 미지정으로 재시도(Auto)
        stream = await navigator.mediaDevices.getUserMedia({ audio: { ...base.audio, deviceId: undefined } });
      }

      // 디버그: 실제 잡힌 마이크 라벨을 저장(한번만)
      try {
        const track = stream.getAudioTracks()[0];
        if (track?.label) localStorage.setItem("micDeviceLabel", track.label);
      } catch {}

      mrStreamRef.current = stream;
      
      let options = { mimeType: "audio/webm;codecs=opus" };
      if (!MediaRecorder.isTypeSupported(options.mimeType)) {
        options = { mimeType: "audio/ogg;codecs=opus" };
      }
      if (!MediaRecorder.isTypeSupported(options.mimeType)) {
        options = { mimeType: "audio/wav" };
      }
      const mr = new MediaRecorder(stream, options);

      chunksRef.current = [];
      mr.ondataavailable = (e)=>{ if(e.data?.size) chunksRef.current.push(e.data); };
      mr.onstart = () => { setListening(true); onListeningChange?.(true); window.dispatchEvent(new Event("mro:mic:start")); };
      
      mr.onstop = async () => {
        setListening(false);
        window.dispatchEvent(new Event("mro:mic:stop"));
        try {
          const mime = mr.mimeType || "audio/webm";
          const ext  = (mime.split("/")[1] || "webm").split(";")[0]; // webm/ogg/wav
      
          const blob = new Blob(chunksRef.current, { type: mime });
          const fd = new FormData();
          fd.append("audio", blob, `audio.${ext}`);   // ✅ 파일명/확장자 함께
          if (lang) fd.append("lang", lang);
      
          const res = await fetch("/stt", { method: "POST", body: fd });
          const json = await res.json();
          if (json?.text) onFinal?.(json.text);
        } catch(e) {
          console.warn("STT upload error:", e?.message);
        } finally {
          chunksRef.current = [];
          if (stream) stream.getTracks().forEach(t=>t.stop());
          mrStreamRef.current = null;
        }
      };

      mr.start();
      mrRef.current = mr;
      return true;
    } catch(e){ console.warn("getUserMedia error:", e?.message); return false; }
  };

  const onPickFile = async (e) => {
    const file = e.target.files?.[0]; if(!file) return;
    try {
      setListening(true); onListeningChange?.(true); window.dispatchEvent(new Event("mro:mic:start"));
      const fd = new FormData(); fd.append("audio", file, file.name||"audio");
      if (lang) fd.append("lang", lang);
      const res = await fetch("/stt", { method:"POST", body:fd });
      const json = await res.json();
      if (json?.text) onFinal?.(json.text);
    } finally {
      setListening(false); onListeningChange?.(false); window.dispatchEvent(new Event("mro:mic:stop"));
      e.target.value = "";
    }
  };

  const toggle = async () => {
    if (!listening) {
      wantRef.current = true;
      // ✅ UI는 즉시 반응
      setListening(true);
      onListeningChange?.(true);
      window.dispatchEvent(new Event("mro:mic:start"));
  
      let ok = false;
      if (mode === "sr") ok = startSR();
      if (!ok && (supportsMR || mode === "mr")) ok = await startMR();
      if (!ok) setTimeout(()=>fileInputRef.current?.click(), 0);
    } else {
      forceStopAll();
      onListeningChange?.(false);
      window.dispatchEvent(new Event("mro:mic:stop"));
    }
  };

  return (
    <>
      <input
        ref={fileInputRef}
        type="file"
        accept="audio/*"
        capture="microphone"
        className="hidden"
        onChange={onPickFile}
      />
      <button
        onClick={toggle}
        aria-pressed={listening}
        className={`p-2 rounded-full shadow-md transition
                   ${listening ? "bg-red-500 animate-pulse" : "bg-blue-500 hover:bg-blue-600"}`}
        title={listening ? "탭하여 종료" : "탭하여 시작"}
      >
        <Mic size={18} />
      </button>
    </>
  );
}

