import React, { useEffect, useState } from "react";

export default function MicSelectBox({ className="" }) {
  const [list, setList] = useState([]);
  const [value, setValue] = useState(() => localStorage.getItem("micDeviceId") || "auto");

  const refresh = async () => {
    try {
      // 라벨을 보려면 권한이 있어야 하는 브라우저가 많음 → 한 번 권한 요청
      try { await navigator.mediaDevices.getUserMedia({ audio: true }); } catch {}
      const devs = await navigator.mediaDevices.enumerateDevices();
      const mics = devs.filter(d => d.kind === "audioinput");
      setList(mics);
    } catch {}
  };

  useEffect(() => {
    refresh();
    navigator.mediaDevices?.addEventListener?.("devicechange", refresh);
    return () => navigator.mediaDevices?.removeEventListener?.("devicechange", refresh);
  }, []);

  const onChange = (e) => {
    const v = e.target.value;
    setValue(v);
    localStorage.setItem("micDeviceId", v); // "auto" or deviceId
  };

  return (
    <label className={`flex items-center gap-2 text-xs text-gray-600 ${className}`}>
      <span className="hidden sm:inline">Mic</span>
      <select
        value={value}
        onChange={onChange}
        className="px-2 py-1 rounded-md border bg-white max-w-[180px]"
      >
        <option value="auto">Auto (system)</option>
        {list.map(d => (
          <option key={d.deviceId || Math.random()} value={d.deviceId}>
            {d.label || "Microphone"}
          </option>
        ))}
      </select>
    </label>
  );
}

import React, { useEffect, useMemo, useCallback, useRef } from "react";
import QRCode from "react-qr-code";
import { useNavigate } from "react-router-dom";
import socket from "../socket";

import languages from "../constants/languages";

const QRCodeBox = ({ roomId, fromLang }) => {
  const navigate = useNavigate();
  const movedRef = useRef(false);

  // 초대 링크 (닉네임 파라미터 제거)
  const link = useMemo(() => {
    const base = new URL(`${window.location.origin}/`);
    base.searchParams.set("roomId", roomId);
    base.searchParams.set("hostLang", fromLang || "");
    base.searchParams.set("v", Date.now().toString());
    return base.toString();
  }, [roomId, fromLang]);

  // ✅ 방 주인(호스트)은 방을 생성하고 join
  useEffect(() => {
    if (!roomId || !fromLang) return;
    // ✅ 수정: 방 생성 이벤트를 먼저 보냄
    socket.emit("create-room", { roomId, fromLang });
    // 기존 join 이벤트는 그대로 유지 (participantId 추가)
    socket.emit("join", { roomId, fromLang, participantId: socket.id });
  }, [roomId, fromLang]);


  // 페이지가 백그라운드면 OS 알림
  const notifyNative = (title, body) => {
    try {
      if ("Notification" in window) {
        if (Notification.permission === "default") Notification.requestPermission().catch(()=>{});
        if (Notification.permission === "granted" && document.hidden) {
          new Notification(title || "Mr.O", { body: body || "" });
        }
      }
      if (navigator?.vibrate) navigator.vibrate([120,60,120]);
    } catch (_) {}
  };

  // ✅ 게스트가 들어오면 자동 이동 (다중 이벤트 수신)
  useEffect(() => {
    const onJoined = (data) => {
      // ✅ 자기 자신이 보낸 이벤트면 무시
      if (data?.socketId === socket.id) return;
      // 🔔 호스트 화면이 내려가 있어도 알림 표시
      notifyNative("게스트가 입장했습니다", "화면을 다시 열어 대화를 시작하세요.");

      if (movedRef.current) return;
      movedRef.current = true;
      navigate(`/room/${roomId}`, { state: { fromLang } });
    };

    socket.on("guest:joined", onJoined);
    socket.on("user-joined", onJoined);
    socket.on("userJoined", onJoined);

    return () => {
      socket.off("guest:joined", onJoined);
      socket.off("user-joined", onJoined);
      socket.off("userJoined", onJoined);
    };
  }, [navigate, roomId, fromLang]);

  const copyToClipboard = useCallback(() => {
    navigator.clipboard.writeText(link).then(() => alert("📋 링크 복사됨"));
  }, [link]);

  return (
    <div className="w-full flex flex-col items-center gap-4">
      <h2 className="text-lg font-semibold text-center">
        상대방에게 아래 링크(또는 QR)를 보내세요
      </h2>

      <div className="text-sm text-gray-600">
        내 언어:
        <span className="ml-2 px-2 py-1 rounded-lg bg-gray-100">
          {languages.find((l) => l.code === fromLang)?.label || fromLang}
        </span>
      </div>

      {/* 링크 박스 */}
      <div className="w-full max-w-xs bg-gray-100 p-4 rounded-xl shadow overflow-x-auto">
        <div
          className="text-blue-600 underline text-center cursor-pointer break-all"
          onClick={copyToClipboard}
          title="클릭하면 링크가 복사됩니다"
        >
          {link}
        </div>
        <p className="text-xs mt-2 text-gray-500 text-center">(클릭 시 복사)</p>
      </div>

      {/* QR */}
      <div className="bg-white p-4 rounded-lg shadow-md">
        <QRCode
          value={link}
          size={200}
          bgColor="#FFFFFF"
          fgColor="#000000"
          level="M"
        />
      </div>
    </div>
  );
};

export default QRCodeBox;

