// ✅ useMicLevel.js (micLevel 상태 노출용으로 확장)
import { useEffect, useRef, useState } from "react";

export default function useMicLevel(stream) {
  const [micLevel, setMicLevel] = useState(0);
  const audioContextRef = useRef(null);
  const analyserRef = useRef(null);
  const dataArrayRef = useRef(null);

  useEffect(() => {
    if (!stream) return;

    audioContextRef.current = new AudioContext();
    const source = audioContextRef.current.createMediaStreamSource(stream);
    const analyser = audioContextRef.current.createAnalyser();
    analyser.fftSize = 32;

    const bufferLength = analyser.frequencyBinCount;
    const dataArray = new Uint8Array(bufferLength);

    source.connect(analyser);

    analyserRef.current = analyser;
    dataArrayRef.current = dataArray;

    const tick = () => {
      analyser.getByteFrequencyData(dataArray);
      const avg = dataArray.reduce((a, b) => a + b, 0) / bufferLength;
      setMicLevel(parseFloat((avg / 255).toFixed(3))); // 소수점 3자리로 고정
      requestAnimationFrame(tick);
    };
    tick();

    return () => {
      audioContextRef.current.close();
    };
  }, [stream]);

  return micLevel;
}

import { useEffect, useState } from "react";

export default function usePWAInstall() {
  const [deferredPrompt, setDeferredPrompt] = useState(null);

  useEffect(() => {
    const handler = (e) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };
    window.addEventListener("beforeinstallprompt", handler);
    return () => window.removeEventListener("beforeinstallprompt", handler);
  }, []);

  const promptInstall = async () => {
    if (!deferredPrompt) return false;
    deferredPrompt.prompt();
    const { outcome } = await deferredPrompt.userChoice;
    setDeferredPrompt(null);
    return outcome === "accepted";
  };

  return { canInstall: !!deferredPrompt, promptInstall };
}

import { useEffect, useRef } from "react";
import { createSocket } from "../socket";

/**
 * 실시간 STT 스트리밍용 훅
 * - isRecording=true 면 마이크 캡처 시작 → 16k PCM으로 다운샘플 → 100ms 단위 base64 전송
 *
 * props:
 * onFinal   : (msg) => void        // 최종 결과 콜백  (msg: { id, text })
 * onPartial : (text) => void       // 중간 결과 콜백 (선택)
 * isRecording: boolean             // 녹음 on/off
 * lang      : string               // 언어코드 (기본 "ko-KR")
 *
 * 반환값 없음 (side-effect 전용)
 */
export default function useWhisperStream({
  onFinal,
  onPartial,
  isRecording,
  lang = "ko-KR",
}) {
  const socketRef = useRef(null);
  const ctxRef = useRef(null);
  const nodeRef = useRef(null);
  const mediaRef = useRef(null);
  const bufRef = useRef(new Float32Array(0));
  const sendingRef = useRef(false);
  const startedRef = useRef(false);

  const OUT_RATE = 16000;
  const CHUNK_MS = 100;

  // 소켓 초기화 (마운트 시 1회)
  useEffect(() => {
    // 소켓 1회 생성
    if (!socketRef.current) {
      socketRef.current = createSocket();
    }
  }, []);

  // 서버 → 클라이언트 STT 이벤트 수신 연결
  useEffect(() => {
    const s = socketRef.current;
    if (!s) return;
    const onP = ({ text }) => onPartial && onPartial(text);
    const onF = ({ id, text }) => onFinal && onFinal({ id, text });
    s.on("stt_partial", onP);
    s.on("stt_final", onF);
    return () => {
      s.off("stt_partial", onP);
      s.off("stt_final", onF);
    };
  }, [onPartial, onFinal]);

  // 녹음 on/off 감시
  useEffect(() => {
    if (isRecording) startCapture();
    else stopCapture();

    return () => {
      stopCapture();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isRecording, lang]);

  async function startCapture() {
    if (startedRef.current) return;
    startedRef.current = true;

    // 서버에 STT 시작 알림
    socketRef.current?.emit("stt_start", {
      lang,
      sampleRateHz: OUT_RATE,
    });

    const stream = await navigator.mediaDevices.getUserMedia({
      audio: {
        channelCount: 1,
        noiseSuppression: true,
        echoCancellation: true,
        autoGainControl: true,
      },
    });

    const ctx = new (window.AudioContext || window.webkitAudioContext)();
    const src = ctx.createMediaStreamSource(stream);

    const proc = ctx.createScriptProcessor(4096, 1, 1);
    proc.onaudioprocess = (e) => {
      const input = e.inputBuffer.getChannelData(0);
      bufRef.current = concatFloat32(bufRef.current, input);

      const inRate = ctx.sampleRate;
      const needOutSamples = Math.floor(OUT_RATE * (CHUNK_MS / 1000));
      const availableOut = Math.floor(
        bufRef.current.length * (OUT_RATE / inRate)
      );

      if (availableOut >= needOutSamples && !sendingRef.current) {
        sendingRef.current = true;

        const down = downsample(
          bufRef.current,
          inRate,
          OUT_RATE,
          needOutSamples
        );
        const pcm16 = floatToInt16(down);
        const b64 = int16ToBase64(pcm16);

        // 오디오 100ms 청크 송신(emit)
        const s = socketRef.current;
        if (s && b64) {
          s.emit("stt_chunk", {
            roomId: window.__ROOM_ID__,
            lang,
            audio: b64,
          });
        }

        const usedSrc = Math.floor((needOutSamples * inRate) / OUT_RATE);
        bufRef.current = bufRef.current.slice(usedSrc);

        sendingRef.current = false;
      }
    };

    src.connect(proc);
    proc.connect(ctx.destination);

    ctxRef.current = ctx;
    nodeRef.current = proc;
    mediaRef.current = stream;
  }

  function stopCapture() {
    if (!startedRef.current) return;
    startedRef.current = false;

    try {
      socketRef.current?.emit("stt_stop");
    } catch {}

    try {
      nodeRef.current?.disconnect();
    } catch {}
    try {
      ctxRef.current?.close();
    } catch {}
    try {
      mediaRef.current?.getTracks()?.forEach((t) => t.stop());
    } catch {}

    bufRef.current = new Float32Array(0);
    sendingRef.current = false;
  }

  // helper functions
  function concatFloat32(a, b) {
    if (!a?.length) return new Float32Array(b);
    const out = new Float32Array(a.length + b.length);
    out.set(a, 0);
    out.set(b, a.length);
    return out;
  }

  function downsample(buf, inRate, outRate, outCount) {
    if (inRate === outRate) {
      return buf.subarray(0, outCount);
    }
    const ratio = inRate / outRate;
    const out = new Float32Array(outCount);
    let i = 0;
    let pos = 0;
    while (i < outCount && pos < buf.length) {
      const nextPos = (i + 1) * ratio;
      let sum = 0,
        cnt = 0;
      while (pos < nextPos && pos < buf.length) {
        sum += buf[Math.floor(pos)];
        cnt++;
        pos++;
      }
      out[i++] = cnt ? sum / cnt : 0;
    }
    return out;
  }

  function floatToInt16(f32) {
    const out = new Int16Array(f32.length);
    for (let i = 0; i < f32.length; i++) {
      let s = Math.max(-1, Math.min(1, f32[i]));
      out[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
    }
    return out;
  }

  function int16ToBase64(int16) {
    const u8 = new Uint8Array(int16.buffer);
    let bin = "";
    for (let i = 0; i < u8.byteLength; i++) bin += String.fromCharCode(u8[i]);
    return btoa(bin);
  }

  return {};
}

// src/media/getMic.js (새 파일)
let cachedStream = null;
export async function getMicOnce() {
  if (cachedStream) return cachedStream;
  cachedStream = await navigator.mediaDevices.getUserMedia({
    audio: { echoCancellation: true, noiseSuppression: true }
  });
  return cachedStream;
}

import { useEffect, useState } from "react";
import { v4 as uuidv4 } from "uuid";
import { useNavigate, useLocation } from "react-router-dom";
import QRCodeBox from "../components/QRCodeBox";
import socket from "../socket";

import languages from "../constants/languages";

const Home = () => {
  const navigate = useNavigate();
  const location = useLocation();

  const [selectedLang, setSelectedLang] = useState(() => localStorage.getItem("myLang") || "en");
  const [guestNick, setGuestNick] = useState(""); // 유지(안 씀)
  const [roomId, setRoomId] = useState(null);
  const [isCreator, setIsCreator] = useState(false);

  useEffect(() => {
    const query = new URLSearchParams(location.search);
    const incomingRoomId = query.get("roomId");
    if (incomingRoomId) {
      // ✅ QR로 들어온 guest 플로우
      setRoomId(incomingRoomId);
      setIsCreator(false);
      setSelectedLang(localStorage.getItem("myLang") || "ko");
      setGuestNick(localStorage.getItem("myNick") || "");
      // 닉네임은 쓰지 않으므로 비워둠(라벨은 ChatScreen에서 "guest"로 처리)
      try { localStorage.setItem("myNick", ""); } catch {}
    } else {
      // ✅ 호스트 플로우
      const newId = uuidv4();
      setRoomId(newId);
      setIsCreator(true);
      setSelectedLang(localStorage.getItem("myLang") || "en");
    }
  }, [location.search]);

  useEffect(() => {
    if (!roomId) return;
    const onJoined = () => {
      const myNick = localStorage.getItem("myNick") || "";
      navigate(`/room/${roomId}`, { state: { fromLang: selectedLang, myNick } });
    };
    socket.on("user-joined", onJoined);
    return () => socket.off("user-joined", onJoined);
  }, [roomId, selectedLang, navigate]);

  const handleNext = () => {
    if (!roomId) return;
    // ✅ guest 플로우는 닉네임 없이 입장(라벨은 ChatScreen에서 "guest")
    const myNick = ""; 
    localStorage.setItem("myNick", myNick);
    localStorage.setItem("myLang", selectedLang);
    socket.emit("join", { roomId, fromLang: selectedLang, nick: undefined });
    navigate(`/room/${roomId}`, { state: { fromLang: selectedLang, myNick } });
  };

  useEffect(() => {
    if (selectedLang) localStorage.setItem("myLang", selectedLang);
  }, [selectedLang]);

  const opts = Array.isArray(languages) && languages.length
    ? languages
    : [
        { code: "en", label: "English" },
        { code: "ko", label: "Korean" },
        { code: "ja", label: "Japanese" },
        { code: "zh", label: "Chinese" },
      ];

  return (
    <div className="min-h-screen bg-gray-100 flex flex-col items-center justify-center p-6">
      {!roomId ? (
        <p>방을 불러오는 중...</p>
      ) : isCreator ? (
        <>
          <h1 className="text-xl font-bold mb-4">Mr. O - 언어 선택</h1>
          <p className="text-sm text-gray-600 mb-2">👤 <span className="font-semibold">내 언어</span>를 선택해주세요</p>
          <select
            className="px-3 py-2 rounded-xl bg-white shadow text-black"
            value={selectedLang}
            onChange={(e) => setSelectedLang(e.target.value)}
          >
            {opts.map((l) => (
              <option key={l.code} value={l.code}>{(l.label || l.code).toString()}</option>
            ))}
          </select>

          <div className="mt-4">
            <QRCodeBox roomId={roomId} fromLang={selectedLang} />
          </div>
        </>
      ) : (
        <>
          <h1 className="text-xl font-bold mb-4">Mr. O - 언어 선택</h1>
          <p className="text-sm text-gray-600 mb-2">👤 <span className="font-semibold">내 언어</span>를 선택해주세요</p>
          <select
            className="px-3 py-2 rounded-xl bg-white shadow text-black mb-3"
            value={selectedLang}
            onChange={(e) => setSelectedLang(e.target.value)}
          >
            {opts.map((l) => (
              <option key={l.code} value={l.code}>{(l.label || l.code).toString()}</option>
            ))}
          </select>

          {/* ✅ 닉네임 입력 박스 제거 (guest는 닉네임 없이 입장) */}

          <button onClick={handleNext} className="bg-blue-500 text-white px-6 py-2 rounded">
            다음
          </button>
        </>
      )}
    </div>
  );
};

export default Home;

@tailwind base;
@tailwind components;
@tailwind utilities;

body {
