  white-space: pre-wrap; overflow: hidden;
}
/* 입력창 우측에 뜨는 파란 웨이브 (듣는 중 표시) */
.listening-wave {
  position: absolute;
  right: 10px;
  bottom: 10px;
  height: 18px;
  display: flex;
  gap: 3px;
