  animation: wavebounce 900ms ease-in-out infinite;
  border-radius: 2px;
  height: 6px;
}
.listening-wave span:nth-child(2){ animation-delay: .1s }
.listening-wave span:nth-child(3){ animation-delay: .2s }
.listening-wave span:nth-child(4){ animation-delay: .3s }
.listening-wave span:nth-child(5){ animation-delay: .4s }
.listening-wave { pointer-events: none; }

@keyframes wavebounce {
  0%   { height: 6px;  opacity:.4; transform: translateY(0) }
  50%  { height: 16px; opacity:1;  transform: translateY(-1px) }
  100% { height: 6px;  opacity:.4; transform: translateY(0) }
}

// AudioProcessor.js
export default class AudioProcessor {
  constructor({ onChunk, silenceDuration = 1000 }) {
    this.onChunk = onChunk; // 청크가 완성되면 호출되는 콜백
    this.audioContext = null;
    this.processor = null;
    this.mediaStream = null;
    this.sourceNode = null;

    this.buffer = [];
    this.isSpeaking = false;
    this.silenceMs = 0;

    this.frameSize = 320; // 20ms @ 16kHz mono
    this.hopSize = 160;   // 10ms 홉
    this.sampleRate = 16000;
    this.silenceThreshold = 0.01;
    this.silenceDuration = silenceDuration; // 무음 지속 시간(ms) → 청크 종료 기준
  }

  async start(stream) {
    this.audioContext = new AudioContext({ sampleRate: this.sampleRate });
    this.mediaStream = stream;
    this.sourceNode = this.audioContext.createMediaStreamSource(stream);

    const workletURL = URL.createObjectURL(new Blob([`
      class VADProcessor extends AudioWorkletProcessor {
        constructor() {
          super();
          this.buffer = [];
          this.hopSize = 160;
          this.port.onmessage = (e) => {
            this.silenceThreshold = e.data.silenceThreshold;
          };
        }

        process(inputs) {
          const input = inputs[0][0];
          if (!input) return true;

          let sum = 0;
          for (let i = 0; i < input.length; i++) {
            sum += input[i] * input[i];
          }
          const rms = Math.sqrt(sum / input.length);
          const isSpeaking = rms > this.silenceThreshold;

          this.port.postMessage({
            type: "data",
            audio: input,
            isSpeaking,
            rms
          });

          return true;
        }
      }
      registerProcessor("vad-processor", VADProcessor);
    `], { type: "application/javascript" }));

    await this.audioContext.audioWorklet.addModule(workletURL);

    this.processor = new AudioWorkletNode(this.audioContext, "vad-processor");
    this.processor.port.postMessage({ silenceThreshold: this.silenceThreshold });

    this.processor.port.onmessage = (event) => {
      const { audio, isSpeaking } = event.data;

      this.buffer.push(...audio);

      if (isSpeaking) {
        this.isSpeaking = true;
        this.silenceMs = 0;
      } else if (this.isSpeaking) {
        this.silenceMs += this.frameSize * 1000 / this.sampleRate;
        if (this.silenceMs > this.silenceDuration) {
          const chunk = new Float32Array(this.buffer);
          this.onChunk?.(chunk);
          this.buffer = [];
          this.isSpeaking = false;
          this.silenceMs = 0;
        }
      }
    };

    this.sourceNode.connect(this.processor).connect(this.audioContext.destination);
  }

  stop() {
    if (this.processor) this.processor.disconnect();
    if (this.sourceNode) this.sourceNode.disconnect();
    if (this.audioContext) this.audioContext.close();

    this.processor = null;
    this.sourceNode = null;
    this.audioContext = null;
    this.buffer = [];
    this.isSpeaking = false;
    this.silenceMs = 0;
  }
}

// src/utils/recents.js
const KEY = "mro:recents";
const MAX = 50;

export function loadRecents() {
  try {
    const raw = localStorage.getItem(KEY);
    return raw ? JSON.parse(raw) : [];
  } catch {
    return [];
  }
}

function saveRecents(list) {
  try {
    localStorage.setItem(KEY, JSON.stringify(list.slice(0, MAX)));
  } catch {}
}

/**
 * 최근 목록에 방을 올리고 마지막 사용 시각을 갱신
 * - 없으면 추가, 있으면 맨 앞으로 이동
 */
export function touchRecent({ roomId, myLang, peerLang, myName = "Me", peerName = "Partner" }) {
  if (!roomId) return;
  const now = Date.now();
  const list = loadRecents().filter((r) => r.roomId !== roomId);
  list.unshift({ roomId, myLang, peerLang, myName, peerName, lastSeen: now });
  saveRecents(list);
}

/** 최근 목록에서 방 제거 */
export function removeRecent(roomId) {
  if (!roomId) return;
  const list = loadRecents().filter((r) => r.roomId !== roomId);
  saveRecents(list);
}
